code.C:
#include <stdio.h>

struct Numbers {int a; int b;};

int addNumbers(struct Numbers n) {return n.a + n.b;}

int main() {
    struct Numbers n;
    if (scanf("%d", &n.a) != 1) return 0;
    if (scanf("%d", &n.b) != 1) return 0;
    printf("%d\n", addNumbers(n));
    return 0;
}

